public boolean xyBalance(String str) {
    int unbalance = 0;
    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == 'x') {
            unbalance++;
        } else if (str.charAt(i) == 'y') {
            unbalance--;
        }
    }
    return unbalance == 0;
}

public int makeChocolate(int small, int big, int goal) {
    if (big * 5 > goal) {
        int maxBig = goal / 5;
        if (maxBig > big) maxBig = big;
        goal -= maxBig * 5;
        if (goal > small) return -1;
        return goal;
    } else {
        goal -= big * 5;
        if (goal > small) return -1;
        return goal;
    }
}

